// JavaScript / Node.js — conditional prompting with rule-based router
// npm install @anthropic-ai/sdk

import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();   // reads ANTHROPIC_API_KEY from env

const TEMPLATES = {
  "payment.failed":
    "You are a payments analyst. Diagnose the failure reason and suggest one fix.",
  "fraud.alert":
    "You are a risk analyst. Evaluate the event and output JSON: " +
    '{"risk_level":"high|medium|low","action":"string"}.',
  fallback:
    "You are a data analyst. Summarise this event in two sentences.",
};

/** Rule-based router — zero LLM cost, deterministic. */
function route(event) {
  return TEMPLATES[event.type] ?? TEMPLATES.fallback;
}

async function analyseEvent(event) {
  const system = route(event);
  const msg = await client.messages.create({
    model: "claude-haiku-4-5",
    max_tokens: 256,
    system,
    messages: [{ role: "user", content: JSON.stringify(event, null, 2) }],
  });
  return msg.content[0].text;
}

// Demo
const events = [
  { type: "payment.failed", amount: 4900, failure_code: "insufficient_funds" },
  { type: "fraud.alert",    risk_score: 91, ip_country: "XX", card_country: "US" },
  { type: "user.signed_up", email: "alice@example.com" },   // hits fallback
];

for (const ev of events) {
  console.log(`\n[${ev.type}]`);
  console.log(await analyseEvent(ev));
}

# Production multi-signal router: combines regex pre-check + LLM classifier
# so fast/obvious cases pay zero LLM cost.
import re, json
import anthropic

client = anthropic.Anthropic()

# Tier 1 — regex (O(1), free)
FAST_PATTERNS = {
    "billing":   re.compile(r"\b(invoice|charged|refund|subscription|payment)\b", re.I),
    "technical": re.compile(r"\b(error|bug|api|sdk|exception|stacktrace|401|500)\b", re.I),
}

def fast_classify(text: str) -> str | None:
    for label, pat in FAST_PATTERNS.items():
        if pat.search(text):
            return label
    return None   # no match → escalate to LLM

# Tier 2 — LLM (used only for ambiguous messages)
LLM_CLASSIFIER = """
Classify the support message. Reply with JSON only:
{"category": "billing|technical|general", "confidence": 0.0-1.0}
"""

def llm_classify(text: str) -> tuple[str, float]:
    r = client.messages.create(
        model="claude-haiku-4-5", max_tokens=48,
        messages=[{"role": "user",
                   "content": f"{LLM_CLASSIFIER}\n\nMessage: {text}"}],
    )
    d = json.loads(r.content[0].text)
    return d.get("category", "general"), float(d.get("confidence", 0.5))

THRESHOLD = 0.72

def smart_route(message: str) -> tuple[str, str]:
    # Try regex first
    label = fast_classify(message)
    if label:
        return label, "regex"

    # Fall back to LLM
    label, conf = llm_classify(message)
    if conf < THRESHOLD:
        label = "general"
    return label, "llm"

if __name__ == "__main__":
    samples = [
        "I was charged twice for the Pro plan.",    # should hit billing (regex)
        "Getting 401 on /v1/chat/completions.",     # technical (regex)
        "Can I export my data somewhere?",          # general (LLM needed)
    ]
    for s in samples:
        route, method = smart_route(s)
        print(f"[{method:5s}] {route:10s} | {s}")
